    <text x="142" y="147" fill="#e4e4e7" font-size="14" text-anchor="end" font-family="sans-serif">BitMine</text>
    <text x="142" y="237" fill="#e4e4e7" font-size="14" text-anchor="end" font-family="sans-serif">SharpLink</text>
